prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orgId ?choreo WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Anzeigeformualr ausfüllen")))
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:belongsTo ?org . ?org tai:organizationId ?orgId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orgId ?taskName WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("anzeige")) &&
    CONTAINS(LCASE(STR(?taskName)), LCASE("aus")) &&
    CONTAINS(LCASE(STR(?taskName)), LCASE("füllen"))
  )

  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model bbo:name ?modelName .
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org tai:organizationId ?orgId .
  }
}
LIMIT 25
